#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int a[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &a[i]);
        }
        int yb, mb, db;
        scanf("%d %d %d", &yb, &mb, &db);
        int yc, mc, dc;
        scanf("%d %d %d", &yc, &mc, &dc);
        int age = 0;
        for (int y = yb; y <= yc; y++) {
            if (y == yb) {
                for (int m = mb; m <= N; m++) {
                    if (m == mb) {
                        age += a[m - 1] - db + 1;
                    } else {
                        age += a[m - 1];
                    }
                }
            } else if (y == yc) {
                for (int m = 1; m <= mc; m++) {
                    if (m == mc) {
                        age += dc;
                    } else {
                        age += a[m - 1];
                    }
                }
            } else {
                for (int m = 1; m <= N; m++) {
                    age += a[m - 1];
                }
            }
            if (y % 4 == 0 && m == N) {
                age++;
            }
        }
        printf("%d\n", age);
    }
    return 0;
}

